# Write a C# program to parse the binlog and extract errors/warnings
mkdir -p /tmp/binlog-analyzer && cat > /tmp/binlog-analyzer/Program.cs << 'CSHARP'
using System;
using System.Collections.Generic;
using System.IO;
using System.Linq;
using Microsoft.Build.Logging.StructuredLogger;

class Program
{
    static void Main(string[] args)
    {
        var binlogPath = args[0];
        var build = BinaryLog.ReadBuild(binlogPath);

        var errors = new List<(string Project, string Code, string Message, string File, int Line)>();
        var warnings = new List<(string Project, string Code, string Message, string File, int Line)>();
        var failedProjects = new HashSet<string>();
        var projectDeps = new Dictionary<string, List<string>>(); // project -> dependencies

        // Collect all nodes recursively
        void Visit(BaseNode node, string currentProject)
        {
            if (node is Project proj)
            {
                currentProject = proj.Name;
            }

            if (node is Error err)
            {
                errors.Add((currentProject ?? "Unknown", err.Code ?? "", err.Message ?? err.Text ?? "", err.File ?? "", err.LineNumber));
                if (currentProject != null) failedProjects.Add(currentProject);
            }

            if (node is Warning warn)
            {
                warnings.Add((currentProject ?? "Unknown", warn.Code ?? "", warn.Message ?? warn.Text ?? "", warn.File ?? "", warn.LineNumber));
            }

            if (node is TreeNode treeNode)
            {
                foreach (var child in treeNode.Children)
                {
                    if (child is BaseNode childNode)
                        Visit(childNode, currentProject);
                }
            }
        }

        Visit(build, null);

        Console.WriteLine("=== BUILD ERRORS ===");
        Console.WriteLine($"Total errors: {errors.Count}");
        Console.WriteLine();

        var grouped = errors.GroupBy(e => e.Project);
        foreach (var group in grouped.OrderBy(g => g.Key))
        {
            Console.WriteLine($"--- Project: {group.Key} ---");
            foreach (var err in group)
            {
                Console.WriteLine($"  [{err.Code}] {err.File}({err.Line}): {err.Message}");
            }
            Console.WriteLine();
        }

        if (warnings.Any())
        {
            Console.WriteLine("=== BUILD WARNINGS (potentially relevant) ===");
            Console.WriteLine($"Total warnings: {warnings.Count}");
            var warnGrouped = warnings.GroupBy(w => w.Project);
            foreach (var group in warnGrouped.OrderBy(g => g.Key))
            {
                Console.WriteLine($"--- Project: {group.Key} ---");
                foreach (var w in group)
                {
                    Console.WriteLine($"  [{w.Code}] {w.File}({w.Line}): {w.Message}");
                }
                Console.WriteLine();
            }
        }

        // Check for MSB3202 (project reference not found) or similar cascading errors
        Console.WriteLine("=== ANALYSIS: Cascading vs Root Cause ===");
        var msbProjectErrors = errors.Where(e => e.Code == "MSB3202" || e.Code == "MSB4236" || e.Message.Contains("could not be loaded")).ToList();
        if (msbProjectErrors.Any())
        {
            Console.WriteLine("Cascading project reference errors:");
            foreach (var e in msbProjectErrors)
            {
                Console.WriteLine($"  {e.Project}: {e.Message}");
            }
        }

        var compileErrors = errors.Where(e => e.Code.StartsWith("CS") || e.Code.StartsWith("FS") || e.Code.StartsWith("VB")).ToList();
        if (compileErrors.Any())
        {
            Console.WriteLine("Compilation errors (likely root causes):");
            foreach (var e in compileErrors)
            {
                Console.WriteLine($"  {e.Project} [{e.Code}] {e.File}({e.Line}): {e.Message}");
            }
        }

        var nugetErrors = errors.Where(e => e.Code.StartsWith("NU")).ToList();
        if (nugetErrors.Any())
        {
            Console.WriteLine("NuGet errors:");
            foreach (var e in nugetErrors)
            {
                Console.WriteLine($"  {e.Project} [{e.Code}]: {e.Message}");
            }
        }
    }
}
CSHARP

