cat > /tmp/binlog-analyzer/Program.cs << 'CSHARP'
using System;
using System.Collections.Generic;
using System.IO;
using System.Linq;
using Microsoft.Build.Logging.StructuredLogger;

class Program
{
    static void Main(string[] args)
    {
        var binlogPath = args[0];
        var build = BinaryLog.ReadBuild(binlogPath);

        var allNodes = new List<(int Depth, string Type, string Text)>();

        void Visit(BaseNode node, int depth, string parentProject)
        {
            string nodeType = node.GetType().Name;
            string text = node.ToString() ?? "";
            string currentProject = parentProject;

            if (node is Project proj)
            {
                currentProject = proj.Name;
                Console.WriteLine($"{"".PadLeft(depth*2)}[Project] {proj.Name} | SourceFilePath={proj.SourceFilePath}");
            }
            else if (node is Error err)
            {
                Console.WriteLine($"{"".PadLeft(depth*2)}[ERROR] Code={err.Code} File={err.File}({err.LineNumber},{err.ColumnNumber}) Text={err.Text}");
            }
            else if (node is Warning warn)
            {
                Console.WriteLine($"{"".PadLeft(depth*2)}[WARN] Code={warn.Code} File={warn.File}({warn.LineNumber}) Text={warn.Text}");
            }
            else if (node is Target target)
            {
                if (target.Name == "ResolvePackageAssets" || target.Name == "ResolveAssemblyReferences" 
                    || target.Name == "CoreCompile" || target.Name == "ResolveProjectReferences"
                    || target.Name == "Build" || target.Name == "Restore" || target.Name == "_GenerateRestoreProjectPathWalk")
                {
                    Console.WriteLine($"{"".PadLeft(depth*2)}[Target] {target.Name} Succeeded={target.Succeeded}");
                }
            }
            else if (node is Item item)
            {
                if (item.NameEquals("PackageReference") || item.NameEquals("ProjectReference") || item.NameEquals("Reference"))
                {
                    Console.WriteLine($"{"".PadLeft(depth*2)}[Item] {item.Name}: {item.Text}");
                }
            }
            else if (node is AddItem addItem)
            {
                if (addItem.Name == "PackageReference" || addItem.Name == "ProjectReference" || addItem.Name == "Reference")
                {
                    Console.WriteLine($"{"".PadLeft(depth*2)}[AddItem] {addItem.Name}:");
                    if (node is TreeNode tn2)
                    {
                        foreach (var c in tn2.Children)
                        {
                            if (c is Item itm)
                                Console.WriteLine($"{"".PadLeft((depth+1)*2)}  -> {itm.Text}");
                        }
                    }
                }
            }
            else if (node is Property prop)
            {
                if (prop.Name == "TargetFramework" || prop.Name == "TargetFrameworks" || prop.Name == "PackageId")
                {
                    Console.WriteLine($"{"".PadLeft(depth*2)}[Property] {prop.Name} = {prop.Value}");
                }
            }

            if (node is TreeNode treeNode)
            {
                foreach (var child in treeNode.Children)
                {
                    if (child is BaseNode childNode)
                        Visit(childNode, depth + 1, currentProject);
                }
            }
        }

        Visit(build, 0, null);

        // Also look at files in the binlog
        Console.WriteLine();
        Console.WriteLine("=== EMBEDDED FILES (SourceFiles from compilation) ===");
        void FindSourceFiles(BaseNode node, int depth)
        {
            if (node is SourceFile sf)
            {
                Console.WriteLine($"  SourceFile: {sf.Name}");
            }
            if (node is SourceFileLine sfl)
            {
                Console.WriteLine($"    Line: {sfl.Text}");
            }
            // Also check for any nodes related to source content
            if (node is CscTask csc)
            {
                Console.WriteLine($"  CscTask found in project");
            }

            if (node is TreeNode treeNode)
            {
                foreach (var child in treeNode.Children)
                {
                    if (child is BaseNode childNode)
                        FindSourceFiles(childNode, depth + 1);
                }
            }
        }
        FindSourceFiles(build, 0);
    }
}
