        {
            Console.WriteLine("ArchivableModel found");
        }

        // Try reading files from the binlog archive
        try
        {
            var reader = new BinLogReader();
            var records = reader.ReadRecords(binlogPath);
            foreach (var record in records)
            {
                if (record?.Args is Microsoft.Build.Framework.BuildMessageEventArgs msg)
                {
                    if (msg.File != null && msg.File.Contains("UserService"))
                    {
                        Console.WriteLine($"  Msg related to UserService: {msg.Message?.Substring(0, Math.Min(200, msg.Message.Length))}");
                    }
                }
            }
        }
        catch (Exception ex)
        {
            Console.WriteLine($"BinLogReader error: {ex.Message}");
        }

        // List all embedded files
        Console.WriteLine();
        Console.WriteLine("=== LISTING EMBEDDED FILES FROM BINLOG ===");
        try
        {
            var reader2 = new BinLogReader();
            var embeddedFiles = new HashSet<string>();
            foreach (var record in reader2.ReadRecords(binlogPath))
            {
                // Check for embedded file info
                var recordArgs = record?.Args;
                if (recordArgs is Microsoft.Build.Framework.BuildErrorEventArgs errArgs)
                {
                    Console.WriteLine($"  Error event: [{errArgs.Code}] {errArgs.File}({errArgs.LineNumber}): {errArgs.Message}");
                }
            }
        }
